40 | /**
41 |  * Eclipseの.classpathに記載されたJARファイルのSHA1ハッシュを計算し、
42 |  * Maven Central REST APIで依存関係情報を検索するクラス。
43 |  */
44 | public class DependencyResolver {
45 | 
46 |     private static final Logger log = AppLogger.get(DependencyResolver.class);
47 | 
48 |     private static final String MAVEN_SEARCH_URL =
49 |             "https://search.maven.org/solrsearch/select?q=1:%s&rows=1&wt=json";
50 | 
51 | 
52 |     private final HttpClient httpClient;
53 | 
54 |     public DependencyResolver() {
55 |         this.httpClient = HttpClient.newBuilder()
56 |                 .connectTimeout(Duration.ofSeconds(10))
57 |                 .sslContext(createTrustAllSslContext())
58 |                 .build();
59 |     }
60 | 
61 |     /**
62 |      * SSLインスペクション環境向けに、証明書検証を行わないSSLContextを生成する。
63 |      */
64 |     private static SSLContext createTrustAllSslContext() {
65 |         TrustManager[] trustAll = new TrustManager[]{
66 |             new X509TrustManager() {
67 |                 @Override public void checkClientTrusted(X509Certificate[] chain, String authType) {}
68 |                 @Override public void checkServerTrusted(X509Certificate[] chain, String authType) {}
69 |                 @Override public X509Certificate[] getAcceptedIssuers() { return new X509Certificate[0]; }
70 |             }
71 |         };
72 |         try {
73 |             SSLContext ctx = SSLContext.getInstance("TLS");
74 |             ctx.init(null, trustAll, new java.security.SecureRandom());
75 |             return ctx;
76 |         } catch (NoSuchAlgorithmException | KeyManagementException e) {
77 |             throw new IllegalStateException("SSL証明書検証バイパス用SSLContextの生成に失敗しました", e);
78 |         }
79 |     }
80 | 
81 |     /**
82 |      * JARが置かれたディレクトリパスのリストを受け取り、Maven依存関係リストに解決して返す。
83 |      * 各ディレクトリに含まれる全ての {@code .jar} ファイルについて解決を行う。
84 |      *
85 |      * @param jarPaths Eclipseの.classpathから取得したディレクトリパス文字列のリスト
86 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ（相対パス解決の基準）
87 |      * @return 解決済みの {@link MavenDependency} リスト
88 |      */
89 |     public static List<MavenDependency> resolve(List<String> jarPaths, Path inputDir) {
90 |         DependencyResolver resolver = new DependencyResolver();
91 |         List<MavenDependency> results = new ArrayList<>();
92 |         for (String jarPath : jarPaths) {
93 |             Path dir = Path.of(jarPath).isAbsolute()
94 |                     ? Path.of(jarPath)
95 |                     : inputDir.resolve(jarPath);
96 |             if (!Files.isDirectory(dir)) {
97 |                 continue;
98 |             }
99 |             try (var stream = Files.list(dir)) {
100 |                 stream.filter(p -> p.getFileName().toString().endsWith(".jar"))
101 |                       .sorted()
102 |                       .forEach(p -> results.add(resolver.resolveJar(p.toString(), inputDir)));
103 |             } catch (IOException e) {
104 |                 log.warn("  [WARN] ディレクトリの読み取りに失敗しました: {}", dir);
105 |             }
106 |         }
107 |         return results;
108 |     }
109 | 
110 |     /**
111 |      * 1つのJARパスを解決する。
112 |      */
113 |     private MavenDependency resolveJar(String jarPath, Path inputDir) {
114 |         Path path = Path.of(jarPath).isAbsolute()
115 |                 ? Path.of(jarPath)
116 |                 : inputDir.resolve(jarPath);
117 | 
118 |         String jarFileName = path.getFileName().toString();
119 |         // 拡張子なしのベース名
120 |         String baseName = jarFileName.endsWith(".jar")
121 |                 ? jarFileName.substring(0, jarFileName.length() - 4)
122 |                 : jarFileName;
123 | 
124 |         log.info("  Resolving: {} ...", jarFileName);
125 | 
126 |         if (!Files.exists(path)) {
127 |             log.warn("  [WARN] JARファイルが見つかりません: {} → systemスコープとして扱います", path);
128 |             log.info("  → not found (system scope): {}", jarFileName);
129 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", jarPath);
130 |         }
131 | 
132 |         String sha1;
133 |         try {
134 |             sha1 = FileUtils.computeSha1(path);
135 |         } catch (Exception e) {
136 |             log.error("  [ERROR] SHA1計算に失敗しました: {} → {}", path, e.getMessage());
137 |             log.info("  → SHA1 error (system scope): {}", jarFileName);
138 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
139 |         }
140 | 
141 |         try {
142 |             String json = callMavenCentralApi(sha1);
143 |             return parseResponse(json, baseName, path.toAbsolutePath().toString());
144 |         } catch (Exception e) {
145 |             log.error("  [ERROR] Maven Central API呼び出しに失敗しました: {} → {}", jarFileName, e.getMessage());
146 |             log.info("  → API error (system scope): {}", jarFileName);
147 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
148 |         }
149 |     }
150 | 
151 |     /**
152 |      * Maven Central Search APIを呼び出してJSONレスポンスを返す。
153 |      * テスト用にprotectedとして定義し、サブクラスでオーバーライド可能にする。
154 |      */
155 |     protected String callMavenCentralApi(String sha1) throws IOException, InterruptedException {
156 |         String url = String.format(MAVEN_SEARCH_URL, sha1);
157 |         HttpRequest request = HttpRequest.newBuilder()
158 |                 .uri(URI.create(url))
159 |                 .timeout(Duration.ofSeconds(10))
160 |                 .GET()
161 |                 .build();
162 |         HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
163 |         return response.body();
164 |     }
165 | 
166 |     // private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\"\\s*:\\s*\"([^\"]+)\"");
167 |     // private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\"\\s*:\\s*\"([^\"]+)\"");
168 |     // private static final Pattern VERSION_PATTERN     = Pattern.compile("\"latestVersion\"\\s*:\\s*\"([^\"]+)\"");
169 |     // private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
170 |     private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\":\"([^\"]+)\"");
171 |     private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\":\"([^\"]+)\"");
172 |     private static final Pattern VERSION_PATTERN     = Pattern.compile("\"v\":\"([^\"]+)\"");
173 |     private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
174 | 
175 |     /**
176 |      * Maven Central APIのJSONレスポンスをパースしてMavenDependencyを返す。
177 |      */
178 |     private static MavenDependency parseResponse(String json, String baseName, String absolutePath) {
179 |         // numFound:0 なら見つからなかった
180 |         Matcher numFoundMatcher = NUM_FOUND_PATTERN.matcher(json);
181 |         if (numFoundMatcher.find()) {
182 |             int numFound = Integer.parseInt(numFoundMatcher.group(1));
183 |             if (numFound == 0) {
184 |                 log.info("  → not found in Maven Central (system scope): {}", baseName);
185 |                 return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
186 |             }
187 |         }
188 | 
189 |         Matcher gMatcher = GROUP_ID_PATTERN.matcher(json);
190 |         Matcher aMatcher = ARTIFACT_ID_PATTERN.matcher(json);
191 |         Matcher vMatcher = VERSION_PATTERN.matcher(json);
192 | 
193 |         if (gMatcher.find() && aMatcher.find() && vMatcher.find()) {
194 |             String groupId    = gMatcher.group(1);
195 |             String artifactId = aMatcher.group(1);
196 |             String version    = vMatcher.group(1);
197 |             log.info("  → found: {}:{}:{}", groupId, artifactId, version);
198 |             return new MavenDependency(groupId, artifactId, version, null, null);
199 |         }
200 | 
201 |         // パースに失敗した場合もsystemスコープ
202 |         log.warn("  [WARN] Maven Central APIレスポンスのパースに失敗しました: {}", baseName);
203 |         log.info("  → parse error (system scope): {}", baseName);
204 |         return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
205 |     }
206 | }
