134 |     /**
135 |      * ソースフォルダ内のファイルを.javaとリソースに振り分けてコピーする。
136 |      *
137 |      * @param baseDir            コピー元のルート（相対パス計算の基点）
138 |      * @param currentDir         現在処理中のディレクトリ
139 |      * @param javaDestBase       .javaファイルのコピー先ベースディレクトリ
140 |      * @param resourceDest       リソースファイルのコピー先ベースディレクトリ（.properties はここへ）
141 |      * @param resourceDestNormal 通常のリソースコピー先（.properties 以外の非.javaファイルはここへ）
142 |      * @param convertToUtf8      true の場合はエンコーディング変換を行う
143 |      * @param sourceEncoding     変換元エンコーディング
144 |      * @throws IOException ファイルコピーに失敗した場合
145 |      */
146 |     private static void copySourceFolder(Path baseDir, Path currentDir, Path javaDestBase,
147 |                                          Path resourceDest, Path resourceDestNormal,
148 |                                          boolean convertToUtf8, Charset sourceEncoding)
149 |             throws IOException {
150 |         log.debug("  javaDestBase = {}", javaDestBase);
151 |         log.debug("  resourceDest = {}", resourceDest);
152 |         log.debug("  resourceDestNormal = {}", resourceDestNormal);
153 | 
154 |         Files.walk(currentDir)
155 |             .filter(Files::isRegularFile)
156 |             .forEach(srcFile -> {
157 |                 try {
158 |                     Path relative = baseDir.relativize(srcFile);
159 |                     String fileName = srcFile.getFileName().toString();
160 |                     boolean isJava = fileName.endsWith(".java");
161 |                     boolean isProperties = fileName.endsWith(".properties");
162 | 
163 |                     if (isJava) {
164 |                         Path destFile = javaDestBase.resolve(relative);
165 |                         Files.createDirectories(destFile.getParent());
166 |                         if (convertToUtf8) {
167 |                             copyWithEncodingConversion(srcFile, destFile, sourceEncoding);
168 |                             log.debug("  [Java:UTF-8変換] {}", relative);
169 |                         } else {
170 |                             Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
171 |                             log.debug("  [Java:バイナリコピー] {}", relative);
172 |                         }
173 |                     } else if (isProperties && convertToUtf8) {
174 |                         // .properties: Unicode エスケープ展開 + UTF-8 で resourceDest へ
175 |                         Path destFile = resourceDest.resolve(relative);
176 |                         Files.createDirectories(destFile.getParent());
177 |                         copyPropertiesWithConversion(srcFile, destFile, sourceEncoding);
178 |                         log.debug("  [Properties:UTF-8変換] {}", relative);
179 |                     } else {
180 |                         // その他のリソース（バイナリコピー）
181 |                         Path destFile = resourceDestNormal.resolve(relative);
182 |                         Files.createDirectories(destFile.getParent());
183 |                         Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
184 |                         log.debug("  [Resource:バイナリコピー] {}", relative);
185 |                     }
186 |                 } catch (IOException e) {
187 |                     throw new RuntimeException("ファイルコピーに失敗しました: " + srcFile, e);
188 |                 }
189 |             });
190 |         log.info("  Copied source folder: {} → {}", currentDir, javaDestBase);
191 |     }
