193 |     /**
194 |      * Webコンテンツディレクトリを再帰的にコピーする。
195 |      * WEB-INF/lib 直下の .jar ファイルはスキップする。
196 |      * WEB-INF/classes ディレクトリ以下のファイルはすべてスキップする。
197 |      * {@code convertToUtf8=true} の場合、.jsp ファイルはエンコーディング変換を行う。
198 |      *
199 |      * @param srcDir         コピー元ディレクトリ
200 |      * @param destDir        コピー先ディレクトリ
201 |      * @param convertToUtf8  true の場合はエンコーディング変換を行う
202 |      * @param sourceEncoding 変換元エンコーディング（.jsp の pageEncoding が不明な場合に使用）
203 |      * @throws IOException ファイルコピーに失敗した場合
204 |      */
205 |     private static void copyWebContents(Path srcDir, Path destDir,
206 |                                         boolean convertToUtf8, Charset sourceEncoding)
207 |             throws IOException {
208 |         Path excludeJarDir = srcDir.resolve("WEB-INF/lib");
209 |         Path excludeClassesDir = srcDir.resolve("WEB-INF/classes");
210 |         Files.walk(srcDir)
211 |                 .filter(srcPath -> (!srcPath.startsWith(excludeJarDir)
212 |                         || !srcPath.getFileName().toString().endsWith(".jar"))
213 |                         && !srcPath.startsWith(excludeClassesDir))
214 |                 .forEach(srcPath -> {
215 |                     try {
216 |                         Path relative = srcDir.relativize(srcPath);
217 |                         Path destPath = destDir.resolve(relative);
218 |                         if (Files.isDirectory(srcPath)) {
219 |                             Files.createDirectories(destPath);
220 |                             log.debug("  [ディレクトリー作成] {}", relative);
221 |                         } else {
222 |                             Files.createDirectories(destPath.getParent());
223 |                             String fileName = srcPath.getFileName().toString();
224 |                             if (convertToUtf8 && fileName.endsWith(".jsp")) {
225 |                                 Charset jspEncoding = extractJspPageEncoding(srcPath, sourceEncoding);
226 |                                 if (jspEncoding != null) {
227 |                                     copyJspWithConversion(srcPath, destPath, jspEncoding);
228 |                                     log.debug("  [JSP:UTF-8変換] {} (encode={})", relative, jspEncoding);
229 |                                 } else {
230 |                                     // pageEncoding が既に UTF-8 → バイナリコピー
231 |                                     Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
232 |                                     log.debug("  [JSP:バイナリコピー] {}", relative);
233 |                                 }
234 |                             } else {
235 |                                 Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
236 |                                 log.debug("  [Web:バイナリコピー] {}", relative);
237 |                             }
238 |                         }
239 |                     } catch (IOException e) {
240 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcPath, e);
241 |                     }
242 |                 });
243 |     }
