274 |     /**
275 |      * 文字列中の Unicode エスケープシーケンス（&#92;uXXXX 形式）を Unicode 文字に展開する。
276 |      *
277 |      * @param line 入力文字列
278 |      * @return Unicode エスケープを展開した文字列
279 |      */
280 |     static String unescapeUnicode(String line) {
281 |         Matcher m = UNICODE_ESCAPE_PATTERN.matcher(line);
282 |         if (!m.find()) {
283 |             return line;
284 |         }
285 |         m.reset();
286 |         StringBuilder sb = new StringBuilder();
287 |         while (m.find()) {
288 |             int codePoint = Integer.parseInt(m.group(1), 16);
289 |             m.appendReplacement(sb, Matcher.quoteReplacement(String.valueOf((char) codePoint)));
290 |         }
291 |         m.appendTail(sb);
292 |         return sb.toString();
293 |     }
