295 |     /**
296 |      * JSP ファイルの先頭 4KB を ISO-8859-1 で読み込み、{@code pageEncoding} 属性を検出する。
297 |      *
298 |      * <ul>
299 |      *   <li>検出でき、かつ UTF-8 系でない場合: そのエンコーディングの {@link Charset} を返す</li>
300 |      *   <li>検出できない場合: {@code fallback} を返す</li>
301 |      *   <li>検出でき、かつ既に UTF-8 系の場合: {@code null} を返す（呼び出し元でバイナリコピーに切り替える）</li>
302 |      * </ul>
303 |      *
304 |      * @param jspFile  JSP ファイルのパス
305 |      * @param fallback pageEncoding が見つからない場合に返すエンコーディング
306 |      * @return 変換元エンコーディング、または null（既に UTF-8 の場合）
307 |      * @throws IOException ファイル読み込みに失敗した場合
308 |      */
309 |     static Charset extractJspPageEncoding(Path jspFile, Charset fallback) throws IOException {
310 |         // 先頭 4KB を ISO-8859-1 で読み込む（バイト値をそのまま文字として扱うため）
311 |         byte[] bytes = Files.readAllBytes(jspFile);
312 |         int len = Math.min(bytes.length, JSP_PREAMBLE_BYTES);
313 |         String preamble = new String(bytes, 0, len, StandardCharsets.ISO_8859_1);
314 | 
315 |         Matcher m = JSP_PAGE_ENCODING_PATTERN.matcher(preamble);
316 |         if (!m.find()) {
317 |             return fallback;
318 |         }
319 |         String encodingName = m.group(1).trim();
320 |         // 既に UTF-8 系であれば null を返す
321 |         if (encodingName.equalsIgnoreCase("UTF-8") || encodingName.equalsIgnoreCase("UTF8")) {
322 |             return null;
323 |         }
324 |         try {
325 |             return Charset.forName(encodingName);
326 |         } catch (Exception e) {
327 |             // 不明なエンコーディング名の場合は fallback を使用
328 |             log.warn("  [WARN] JSP の pageEncoding が不明です: {} → fallback を使用", encodingName);
329 |             return fallback;
330 |         }
331 |     }
