333 |     /**
334 |      * JSP ファイルを指定エンコードで読み込み、{@code pageEncoding} 属性値を {@code UTF-8} に書き換えて出力する。
335 |      *
336 |      * @param src  コピー元 JSP ファイル
337 |      * @param dest コピー先ファイル
338 |      * @param from 変換元エンコーディング
339 |      * @throws IOException ファイル読み書きに失敗した場合
340 |      */
341 |     static void copyJspWithConversion(Path src, Path dest, Charset from) throws IOException {
342 |         String content = Files.readString(src, from);
343 |         // pageEncoding 属性値を UTF-8 に書き換える（シングルクォートとダブルクォートの両方に対応）
344 |         String converted = content.replaceAll(
345 |                 "(<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*)([\"'])([^\"']+)\\2",
346 |                 "$1$2UTF-8$2");
347 |         Files.writeString(dest, converted, StandardCharsets.UTF_8);
348 |     }
