350 |     /**
351 |      * ソースフォルダのパス文字列をinputDir基点の絶対Pathに解決する。
352 |      * 先頭の '/' は除去して相対パスとして扱う。
353 |      */
354 |     private static Path resolveSourcePath(Path inputDir, String folderPath) {
355 |         String normalized = folderPath.startsWith("/") ? folderPath.substring(1) : folderPath;
356 |         if (normalized.isEmpty()) {
357 |             return inputDir;
358 |         }
359 |         return inputDir.resolve(normalized);
360 |     }
