362 |     /**
363 |      * ソースフォルダ名に "test" が含まれるかどうかを判定する。
364 |      * パスの各セグメントを小文字で比較する。
365 |      */
366 |     static boolean isTestFolder(String folderPath) {
367 |         String lower = folderPath.toLowerCase();
368 |         for (String segment : lower.split("[/\\\\]")) {
369 |             if (segment.equals("test") || segment.startsWith("test-") || segment.endsWith("-test")) {
370 |                 return true;
371 |             }
372 |         }
373 |         return false;
374 |     }
375 | }
