144 |                     log.debug("対話的入力モード開始");
145 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
146 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
147 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
148 |                     log.debug("groupId: {}", groupId);
149 |                     log.debug("artifactId: {}", artifactId);
150 |                     log.debug("version: {}", artifactVersion);
151 |                     // --convertToUtf8 指定時は sourceEncoding も対話入力
152 |                     if (convertToUtf8) {
153 |                         sourceEncoding = promptIfAbsent(reader, "sourceEncoding", sourceEncoding, null);
154 |                     }
155 |                     log.debug("sourceEncoding: {}", sourceEncoding);
156 |                 }
157 |             } else {
158 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
159 |                 if (artifactId == null || artifactId.isBlank()) {
160 |                     artifactId = defaultArtifactId;
161 |                 }
162 |                 if (artifactVersion == null || artifactId.isBlank()) {
163 |                     artifactVersion = DEFAULT_ARTIFACT_VERSION;
164 |                 }
165 |                 log.info("groupId: {}", groupId);
166 |                 log.info("artifactId: {}", artifactId);
167 |                 log.info("version: {}", artifactVersion);
168 |                 // --convertToUtf8 指定時は sourceEncoding も対話入力（--groupId 指定時で未指定の場合）
169 |                 if (convertToUtf8 && (sourceEncoding == null || sourceEncoding.isBlank())) {
170 |                     log.debug("対話的入力モード開始");
171 |                     try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
172 |                         sourceEncoding = promptIfAbsent(reader, "sourceEncoding", sourceEncoding, null);
173 |                     }
174 |                     log.debug("sourceEncoding: {}", sourceEncoding);
175 |                 }
176 |             }
177 | 
178 |             // --convertToUtf8 指定時の sourceEncoding バリデーション
179 |             Charset srcCharset = null;
180 |             if (convertToUtf8) {
181 |                 try {
182 |                     srcCharset = Charset.forName(sourceEncoding);
183 |                 } catch (Exception e) {
184 |                     log.error("--sourceEncoding が無効な文字セット名です: {}", sourceEncoding);
185 |                     return 1;
186 |                 }
187 |             }
188 | 
189 |             // 出力先は outputDir/artifactId
190 |             Path outputPath = outputDir.toPath().resolve(artifactId);
191 |             if (outputPath.toFile().exists()) {
192 |                 log.error("出力先ディレクトリがすでに存在しています: {}", outputPath);
193 |                 return 1;
194 |             }
195 | 
196 |             log.info("");
197 |             log.info("=== e2m: Eclipse → Maven 変換開始 ===");
198 |             log.info("  入力: {}", inputPath.toAbsolutePath());
199 |             log.info("  出力: {}", outputPath.toAbsolutePath());
200 | 
201 |             // 3.(続き) JAR依存関係を解決
202 |             log.info("");
203 |             log.info("[3/5] JAR依存関係を解決中...");
204 |             List<MavenDependency> dependencies = DependencyResolver.resolve(eclipseProject.jarPaths(), inputPath);
205 |             long found = dependencies.stream().filter(d -> !"system".equals(d.scope())).count();
206 |             long system = dependencies.stream().filter(d -> "system".equals(d.scope())).count();
207 |             log.info("  Maven Central で見つかった依存: {} 件", found);
208 |             log.info("  system スコープの依存: {} 件", system);
209 | 
210 |             // 4. pom.xml を生成
211 |             log.info("");
212 |             log.info("[4/5] pom.xml を生成中...");
213 |             // --javaTargetVersion が指定された場合はソースバージョンと比較してバリデーション
214 |             JavaVersion sourceVer = eclipseProject.javaSourceVersion();
215 |             if (javaTargetVersion != null) {
216 |                 if (!sourceVer.isUnknown() && javaTargetVersion.compareTo(sourceVer) < 0) {
217 |                     log.error("--javaTargetVersion ({}) はJavaソースバージョン ({}) より低いバージョンを指定することはできません。",
218 |                             javaTargetVersion, eclipseProject.javaSourceVersion());
219 |                     return 1;
220 |                 }
221 |             }
222 |             // 実効 javaTargetVersion を確定（--javaTargetVersion 指定 > Eclipseプロジェクト設定）
223 |             JavaVersion effectiveTargetVersion = (javaTargetVersion != null && !javaTargetVersion.isUnknown())
224 |                     ? javaTargetVersion
225 |                     : eclipseProject.javaTargetVersion();
226 |             PomGenerator.generate(eclipseProject, dependencies, groupId, artifactId, artifactVersion,
227 |                     effectiveTargetVersion, convertToUtf8, outputPath);
228 | 
229 |             // 5. ソース・Webコンテンツをコピー
230 |             log.info("");
231 |             log.info("[5/5] ソースファイルをコピー中...");
232 |             if (convertToUtf8) {
233 |                 log.info("  エンコーディング変換モード: {} → UTF-8", sourceEncoding);
234 |             }
235 |             ProjectCopier.copy(eclipseProject, dependencies, inputPath, outputPath,
236 |                     convertToUtf8, srcCharset, effectiveTargetVersion);
237 | 
238 |             log.info("");
239 |             log.info("=== 変換完了 ===");
240 |             log.info("出力先: {}", outputPath.toAbsolutePath());
241 | 
242 |             // --debug オプション: デバッグ ZIP を生成
243 |             if (debug) {
244 |                 DebugArchiver.archive(inputPath, outputDir.toPath(), outputPath, rawArgs);
245 |             }
246 | 
247 |             return 0;
248 | 
249 |         } catch (Exception e) {
250 |             log.error("変換中にエラーが発生しました: {}", e.getMessage());
251 |             log.debug("スタックトレース:", e);
252 |             return 2;
253 |         }
254 |     }
255 | 
256 |     /**
257 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
258 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
259 |      *
260 |      * @param reader       入力ストリーム
261 |      * @param name         項目名（表示用）
262 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
263 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
264 |      * @return 確定した値
265 |      */
266 |     private static String promptIfAbsent(BufferedReader reader, String name,
267 |             String value, String defaultValue) throws Exception {
268 |         if (value != null && !value.isBlank()) {
269 |             return value;
270 |         }
271 |         while (true) {
272 |             if (defaultValue != null) {
273 |                 System.out.print(name + " [" + defaultValue + "]: ");
274 |             } else {
275 |                 System.out.print(name + ": ");
276 |             }
277 |             System.out.flush();
278 |             String line = reader.readLine();
279 |             if (line == null) {
280 |                 // EOF（パイプ等）の場合はデフォルト値を使用
281 |                 return defaultValue != null ? defaultValue : "";
282 |             }
283 |             String trimmed = line.trim();
284 |             if (trimmed.isEmpty()) {
285 |                 if (defaultValue != null) {
286 |                     return defaultValue;
287 |                 }
288 |                 // 対話的入力モードでのメッセージは，ロガーを使わず，直接System.outに出力
289 |                 System.out.print("  値を入力してください。");
290 |                 continue;
291 |             }
292 |             return trimmed;
293 |         }
294 |     }
295 | 
296 |     // artifactIdとして許可する文字（半角英数字、ハイフン、アンダースコア）以外にマッチする正規表現
297 |     private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");
298 | 
299 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
300 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
301 | 
302 |     /**
303 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
304 |      *
305 |      * @param projectName プロジェクト名
306 |      * @return artifactId用文字列
307 |      */
308 |     public static String convertToArtifactId(String projectName) {
309 |         if (projectName == null || projectName.isBlank()) {
310 |             return "default-artifact";
311 |         }
312 | 
313 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
314 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
315 | 
316 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
317 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
318 | 
319 |         // 3. すべて小文字に変換
320 |         String lowerCase = kebabCase.toLowerCase();
321 | 
322 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
323 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
324 | 
325 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
326 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
327 | 
328 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
329 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
330 | 
331 |         // すべての文字が削られて空になった場合のフォールバック
332 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
333 |     }
334 | 
335 |     /**
336 |      * picocli 用の {@link JavaVersion} 型変換クラス。
337 |      * 変換に失敗した場合は {@link JavaVersion#UNKNOWN_VERSION} を返す。
338 |      */
339 |     static class JavaVersionConverter implements ITypeConverter<JavaVersion> {
340 |         @Override
341 |         public JavaVersion convert(String value) {
342 |             return JavaVersion.of(value);
343 |         }
344 |     }
345 | }
