17 | package com.ibm.jp.automation.e2m;
18 | 
19 | import org.slf4j.Logger;
20 | import org.w3c.dom.Document;
21 | import org.w3c.dom.Element;
22 | 
23 | import javax.xml.parsers.DocumentBuilder;
24 | import javax.xml.parsers.DocumentBuilderFactory;
25 | import javax.xml.transform.OutputKeys;
26 | import javax.xml.transform.Transformer;
27 | import javax.xml.transform.TransformerFactory;
28 | import javax.xml.transform.dom.DOMSource;
29 | import javax.xml.transform.stream.StreamResult;
30 | import java.nio.file.Files;
31 | import java.nio.file.Path;
32 | import java.util.List;
33 | 
34 | /**
35 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
36 |  */
37 | public class PomGenerator {
38 | 
39 |     private static final Logger log = AppLogger.get(PomGenerator.class);
40 | 
41 |     private static final String MAVEN_COMPILER_PLUGIN_VERSION = "3.15.0";
42 |     private static final String MAVEN_WAR_PLUGIN_VERSION = "3.5.1";
43 |     private static final String NATIVE2ASCII_PLUGIN_VERSION = "2.1.1";
44 | 
45 |     private PomGenerator() {}
46 | 
47 |     /**
48 |      * pom.xmlを生成して出力ディレクトリに保存する。
49 |      *
50 |      * @param eclipseProject        パース済みEclipseプロジェクト情報
51 |      * @param dependencies          解決済み依存関係リスト
52 |      * @param groupId               生成するpom.xmlのgroupId
53 |      * @param artifactId            生成するpom.xmlのartifactId
54 |      * @param version               生成するpom.xmlのversion
55 |      * @param effectiveTargetVersion maven.compiler.targetに使用するJavaバージョン。
56 |      * @param convertToUtf8      --convert-to-utf8 オプションが指定されているか
57 |      * @param outputDir          出力ディレクトリ
58 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
59 |      */
60 |     public static void generate(
61 |             EclipseProject eclipseProject,
62 |             List<MavenDependency> dependencies,
63 |             String groupId,
64 |             String artifactId,
65 |             String version,
66 |             JavaVersion effectiveTargetVersion,
67 |             boolean convertToUtf8,
68 |             Path outputDir) throws Exception {
69 | 
70 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
71 |         DocumentBuilder db = dbf.newDocumentBuilder();
72 |         Document doc = db.newDocument();
73 | 
74 |         // <project>
75 |         Element project = doc.createElement("project");
76 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
77 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
78 |         project.setAttribute("xsi:schemaLocation",
79 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
80 |         doc.appendChild(project);
81 | 
82 |         addTextElement(doc, project, "modelVersion", "4.0.0");
83 |         addTextElement(doc, project, "groupId", groupId);
84 |         addTextElement(doc, project, "artifactId", artifactId);
85 |         addTextElement(doc, project, "version", version);
86 | 
87 |         if (eclipseProject.webProject()) {
88 |             addTextElement(doc, project, "packaging", "war");
89 |         }
90 | 
91 |         // <properties>
92 |         JavaVersion javaSourceVersion = eclipseProject.javaSourceVersion();
93 |         JavaVersion javaTargetVersion = effectiveTargetVersion;
94 |         Element properties = doc.createElement("properties");
95 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
96 |         addTextElement(doc, properties, "maven.compiler.source", javaSourceVersion.toString());
97 |         addTextElement(doc, properties, "maven.compiler.target", javaTargetVersion.toString());
98 |         project.appendChild(properties);
99 | 
100 |         // <dependencies>
101 |         boolean hasDependencies = !dependencies.isEmpty() || eclipseProject.webProject();
102 |         if (hasDependencies) {
103 |             Element deps = doc.createElement("dependencies");
104 |             for (MavenDependency dep : dependencies) {
105 |                 Element dependency = doc.createElement("dependency");
106 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
107 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
108 |                 addTextElement(doc, dependency, "version", dep.version());
109 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
110 |                     addTextElement(doc, dependency, "scope", dep.scope());
111 |                 }
112 |                 if (dep.systemPath() != null) {
113 |                     // system スコープの JAR は libs/ にコピーされるため ${project.basedir}/libs/<ファイル名> で参照
114 |                     String fileName = Path.of(dep.systemPath()).getFileName().toString();
115 |                     addTextElement(doc, dependency, "systemPath",
116 |                             "${project.basedir}/libs/" + fileName);
117 |                 }
118 |                 deps.appendChild(dependency);
119 |             }
120 |             // webProject の場合は Java EE / Jakarta EE API を provided で追加
121 |             if (eclipseProject.webProject() && eclipseProject.webVersion() != null) {
122 |                 String webVersion = eclipseProject.webVersion();
123 |                 boolean tooOld = webVersion.startsWith("2");
124 |                 String resolvedVersion = tooOld ? "3.0" : webVersion;
125 |                 JavaEEVersion javaEE = JavaEEVersion.of(resolvedVersion);
126 |                 Element dependency = doc.createElement("dependency");
127 |                 if (tooOld) {
128 |                     log.debug("Web APIのバージョン {} は古すぎるため、3.0に置き換えて依存関係を追加します。", webVersion);
129 |                     deps.appendChild(doc.createComment(
130 |                             " WARNING: Servlet " + webVersion + " は古すぎるため対応する javaee-api dependency が存在しません。"
131 |                             + " Java EE 6 (javaee-api:6.0) に置き換えています。マイグレーションが必要です。 "));
132 |                 }
133 |                 addTextElement(doc, dependency, "groupId", javaEE.getGroupId());
134 |                 addTextElement(doc, dependency, "artifactId", javaEE.getArtifactId());
135 |                 addTextElement(doc, dependency, "version", javaEE.getVersion());
136 |                 addTextElement(doc, dependency, "scope", "provided");
137 |                 deps.appendChild(dependency);
138 |             }
139 |             project.appendChild(deps);
140 |         }
141 | 
142 |         // <build><plugins><plugin> maven-compiler-plugin
143 |         Element build = doc.createElement("build");
144 |         Element plugins = doc.createElement("plugins");
145 |         Element compilerPlugin = doc.createElement("plugin");
146 |         addTextElement(doc, compilerPlugin, "groupId", "org.apache.maven.plugins");
147 |         addTextElement(doc, compilerPlugin, "artifactId", "maven-compiler-plugin");
148 |         addTextElement(doc, compilerPlugin, "version", MAVEN_COMPILER_PLUGIN_VERSION);
149 |         plugins.appendChild(compilerPlugin);
150 |         // webProject の場合は maven-war-plugin を追加
151 |         if (eclipseProject.webProject()) {
152 |             Element warPlugin = doc.createElement("plugin");
153 |             addTextElement(doc, warPlugin, "groupId", "org.apache.maven.plugins");
154 |             addTextElement(doc, warPlugin, "artifactId", "maven-war-plugin");
155 |             addTextElement(doc, warPlugin, "version", MAVEN_WAR_PLUGIN_VERSION);
156 |             Element configuration = doc.createElement("configuration");
157 |             addTextElement(doc, configuration, "failOnMissingWebXml", "false");
158 |             warPlugin.appendChild(configuration);
159 |             plugins.appendChild(warPlugin);
160 |         }
161 |         // --convert-to-utf8 かつ javaTargetVersion <= 8 の場合は native2ascii-maven-plugin を追加
162 |         // javaTargetVersion は 93-96 行で確定済み（javaTargetOverride 優先）
163 |         if (convertToUtf8 && !javaTargetVersion.isUnknown()
164 |                 && javaTargetVersion.compareTo(JavaVersion.Java8) <= 0) {
165 |             Element n2aPlugin = doc.createElement("plugin");
166 |             addTextElement(doc, n2aPlugin, "groupId", "org.codehaus.mojo");
167 |             addTextElement(doc, n2aPlugin, "artifactId", "native2ascii-maven-plugin");
168 |             addTextElement(doc, n2aPlugin, "version", NATIVE2ASCII_PLUGIN_VERSION);
169 |             Element executions = doc.createElement("executions");
170 |             Element execution = doc.createElement("execution");
171 |             addTextElement(doc, execution, "id", "native2ascii-utf8-resources");
172 |             addTextElement(doc, execution, "phase", "process-resources");
173 |             Element goals = doc.createElement("goals");
174 |             addTextElement(doc, goals, "goal", "resources");
175 |             execution.appendChild(goals);
176 |             Element configuration = doc.createElement("configuration");
177 |             addTextElement(doc, configuration, "encoding", "UTF-8");
178 |             addTextElement(doc, configuration, "srcDir", "${project.basedir}/src/main/resources-utf8");
179 |             addTextElement(doc, configuration, "outputDir", "${project.build.outputDirectory}");
180 |             execution.appendChild(configuration);
181 |             executions.appendChild(execution);
182 |             n2aPlugin.appendChild(executions);
183 |             plugins.appendChild(n2aPlugin);
184 |         }
185 |         build.appendChild(plugins);
186 |         project.appendChild(build);
187 | 
188 |         // XMLをファイルに書き出す
189 |         Files.createDirectories(outputDir);
190 |         TransformerFactory tf = TransformerFactory.newInstance();
191 |         Transformer transformer = tf.newTransformer();
192 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
193 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
194 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
195 | 
196 |         Path pomPath = outputDir.resolve("pom.xml");
197 |         transformer.transform(new DOMSource(doc), new StreamResult(pomPath.toFile()));
198 | 
199 |         log.info("Generated: {}", pomPath);
200 |     }
201 | 
202 |     private static void addTextElement(Document doc, Element parent, String tagName, String text) {
203 |         Element el = doc.createElement(tagName);
204 |         el.appendChild(doc.createTextNode(text));
205 |         parent.appendChild(el);
206 |     }
207 | }
