175 |     /**
176 |      * `.settings/org.eclipse.wst.common.component` を解析して Webコンテンツルートを返す。
177 |      * ファイルが存在しない場合は null を返す。
178 |      * 先頭の "/" は除去した相対パスとして返す。
179 |      */
180 |     private static String parseWebContentRoot(Path inputDir, DocumentBuilder builder) {
181 |         Path componentFile = inputDir.resolve(".settings")
182 |                 .resolve("org.eclipse.wst.common.component");
183 | 
184 |         if (!Files.exists(componentFile)) {
185 |             return null;
186 |         }
187 | 
188 |         try {
189 |             Document doc = builder.parse(componentFile.toFile());
190 |             doc.getDocumentElement().normalize();
191 | 
192 |             NodeList resources = doc.getElementsByTagName("wb-resource");
193 |             for (int i = 0; i < resources.getLength(); i++) {
194 |                 Element res = (Element) resources.item(i);
195 |                 if ("defaultRootSource".equals(res.getAttribute("tag"))) {
196 |                     String sourcePath = res.getAttribute("source-path");
197 |                     // 先頭の "/" を除去して相対パスに正規化
198 |                     if (sourcePath.startsWith("/")) {
199 |                         sourcePath = sourcePath.substring(1);
200 |                     }
201 |                     return sourcePath;
202 |                 }
203 |             }
204 |         } catch (Exception e) {
205 |             // ファイルが壊れている場合は null を返す
206 |         }
207 | 
208 |         return null;
209 |     }
