143 |     void resolve_fileNotExists(@TempDir Path tempDir) {
144 |         String missingJar = "lib/missing.jar";
145 |         StubDependencyResolver stubResolver = new StubDependencyResolver("{}");
146 | 
147 |         List<MavenDependency> results = invokeResolveViaReflection(
148 |                 stubResolver, List.of(missingJar), tempDir);
149 | 
150 |         assertEquals(1, results.size());
151 |         MavenDependency dep = results.get(0);
152 |         assertEquals("missing", dep.groupId());
153 |         assertEquals("system", dep.scope());
154 |         assertEquals(missingJar, dep.systemPath());
155 |     }
156 | 
157 |     /**
158 |      * API呼び出しで例外が発生した場合もsystemスコープになることを確認する。
159 |      */
160 |     @Test
161 |     void resolve_apiException(@TempDir Path tempDir) throws Exception {
162 |         Path jar = tempDir.resolve("error.jar");
163 |         Files.write(jar, new byte[]{1});
164 | 
165 |         DependencyResolver errorResolver = new DependencyResolver() {
166 |             @Override
167 |             protected String callMavenCentralApi(String sha1) throws IOException {
168 |                 throw new IOException("Connection refused");
169 |             }
170 |         };
171 | 
172 |         List<MavenDependency> results = invokeResolveViaReflection(
173 |                 errorResolver, List.of(jar.toString()), tempDir);
174 | 
175 |         assertEquals(1, results.size());
176 |         assertEquals("system", results.get(0).scope());
177 |     }
178 | 
179 |     // ─────────────────────────────────────────────────────────────
180 |     // 統合テスト（デフォルトでスキップ）
181 |     // ─────────────────────────────────────────────────────────────
182 | 
183 |     /**
184 |      * 実際のMaven Central APIを呼び出す統合テスト。
185 |      * ネットワークアクセスが必要なため、デフォルトでスキップする。
186 |      * 実行する場合は @Disabled を外してください。
187 |      */
188 |     @Test
189 |     @Disabled("ネットワークアクセスが必要なためデフォルトでスキップ")
190 |     void integration_resolveCommonsLang3(@TempDir Path tempDir) throws Exception {
191 |         // commons-lang3-3.12.0.jar が実際に手元にある場合のみ動作する。
192 |         // テスト用に小さなJARを作ることはできないため、
193 |         // 実際のJARファイルパスを指定して実行すること。
194 |         String jarPath = System.getProperty("test.jar.path", "");
195 |         if (jarPath.isBlank()) {
196 |             System.out.println("test.jar.path システムプロパティが未設定のためスキップします");
197 |             return;
198 |         }
199 |         List<MavenDependency> results = DependencyResolver.resolve(List.of(jarPath), tempDir);
200 |         assertEquals(1, results.size());
201 |         System.out.println("Integration result: " + results.get(0));
202 |     }
203 | 
204 |     // ─────────────────────────────────────────────────────────────
205 |     // ヘルパー
206 |     // ─────────────────────────────────────────────────────────────
207 | 
208 |     /**
209 |      * DependencyResolverのprivateなresolveJarメソッドを
210 |      * スタブインスタンス経由で呼び出すヘルパー。
211 |      * <p>
212 |      * staticのresolve()は内部でnew DependencyResolver()するため、
213 |      * スタブを注入できない。そのためリフレクションで非公開メソッドを直接呼ぶ。
214 |      */
215 |     private static List<MavenDependency> invokeResolveViaReflection(
216 |             DependencyResolver resolver, List<String> jarPaths, Path inputDir) {
217 |         try {
218 |             var method = DependencyResolver.class.getDeclaredMethod(
219 |                     "resolveJar", String.class, Path.class);
220 |             method.setAccessible(true);
221 |             List<MavenDependency> results = new java.util.ArrayList<>();
222 |             for (String jarPath : jarPaths) {
223 |                 results.add((MavenDependency) method.invoke(resolver, jarPath, inputDir));
224 |             }
225 |             return results;
226 |         } catch (Exception e) {
227 |             throw new RuntimeException("リフレクション呼び出しに失敗: " + e.getMessage(), e);
228 |         }
229 |     }
230 | }
