package com.ibm.jp.automation.e2m;

/**
 * {@link JarFile} のMavenスコープを表す列挙型。
 *
 * <p>{@link #toMavenScope()} で {@code pom.xml} の {@code <scope>} 要素に書く文字列を返す。
 * {@link #COMPILE} は Maven のデフォルトスコープに相当するため {@code null} を返す。</p>
 */
public enum JarScope {

    /** Maven の compile スコープ（デフォルト）。{@code <scope>} 要素は出力しない。 */
    COMPILE,

    /** Maven の test スコープ。テスト時のみ使用するライブラリ。 */
    TEST,

    /** Maven の provided スコープ。コンテナが提供するため、デプロイ時には除外する。 */
    PROVIDED;

    /**
     * Maven の {@code <scope>} 要素に書く文字列を返す。
     * {@link #COMPILE} の場合は {@code null} を返す（scope 要素を出力しない）。
     *
     * @return Maven scope 文字列、または {@code null}
     */
    public String toMavenScope() {
        return switch (this) {
            case COMPILE  -> null;
            case TEST     -> "test";
            case PROVIDED -> "provided";
        };
    }
}

